mapper.select:
SELECT 
FROM vso_config_vehicle_occupancy t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.model_code = #{modelCode}


    AND t.enable_flag = #{enableFlag}

ORDER BY t.priority DESC, t.id DESC

SELECT 
FROM vso_config_vehicle_occupancy t
WHERE t.row_valid = 1

    AND t.model_code = #{params.modelCode}


    AND t.order_type = #{params.orderType}


    AND t.store_code = #{params.storeCode}


    AND t.enable_flag = #{params.enableFlag}

ORDER BY t.priority DESC, t.id DESC

